    <hr><div class="form-group"><div class="row"><label class="col-md-2"><?php echo app_lang("gd_frequency"); ?></label><div class="col-md-2"><select name="frequency" id="gd-series-frequency" class="form-control"><?php foreach ($frequencies as $value) { ?><option value="<?php echo $value; ?>"<?php echo ($model_info->frequency ?? "weekly") === $value ? " selected" : ""; ?>><?php echo app_lang("gd_booking_series_frequency_" . $value); ?></option><?php } ?></select></div><label class="col-md-2"><?php echo app_lang("gd_interval"); ?></label><div class="col-md-2"><input type="number" min="1" max="365" name="interval_value" class="form-control" value="<?php echo (int) ($model_info->interval_value ?? 1); ?>"></div><label class="col-md-2 gd-monthly-row"><?php echo app_lang("gd_monthly_day"); ?></label><div class="col-md-2 gd-monthly-row"><input type="number" min="1" max="31" name="monthly_day" class="form-control" value="<?php echo $e($model_info->monthly_day ?? date("j")); ?>"></div></div></div>
    <div class="form-group gd-weekly-row"><label><?php echo app_lang("gd_weekdays"); ?></label><div><?php foreach ($days as $value => $label) { ?><label class="checkbox-inline mr15"><input type="checkbox" name="weekdays[]" value="<?php echo $value; ?>"<?php echo in_array($value, $selected_days, true) ? " checked" : ""; ?>> <?php echo $label; ?></label><?php } ?></div></div>
    <div class="form-group"><div class="row"><label class="col-md-2"><?php echo app_lang("gd_local_start_time"); ?></label><div class="col-md-2"><input type="time" name="local_start_time" class="form-control" required value="<?php echo $e(substr((string) ($model_info->local_start_time ?? "09:00"), 0, 5)); ?>"></div><label class="col-md-2"><?php echo app_lang("gd_local_end_time"); ?></label><div class="col-md-2"><input type="time" name="local_end_time" class="form-control" required value="<?php echo $e(substr((string) ($model_info->local_end_time ?? "10:00"), 0, 5)); ?>"></div><label class="col-md-2"><?php echo app_lang("gd_starts_on"); ?></label><div class="col-md-2"><input type="date" name="starts_on" class="form-control" required value="<?php echo $e($scope === "this_and_future" ? ($from_local_date ?? "") : ($model_info->starts_on ?? date("Y-m-d"))); ?>"></div></div><small class="text-muted"><?php echo app_lang("gd_unit_timezone") . ": " . $e($timezone) . ". " . app_lang("gd_booking_series_overnight_hint"); ?></small></div>
