    <div class="form-group"><div class="row"><label class="col-md-3"><?php echo app_lang("gd_default_booking_status"); ?></label><div class="col-md-3"><select name="default_booking_status" class="form-control"><?php foreach ($default_statuses as $value) { ?><option value="<?php echo $value; ?>"<?php echo ($model_info->default_booking_status ?? "pending_confirmation") === $value ? " selected" : ""; ?>><?php echo app_lang("gd_booking_status_" . $value); ?></option><?php } ?></select></div><label class="col-md-3"><?php echo app_lang("gd_conflict_policy"); ?></label><div class="col-md-3"><select name="conflict_policy" class="form-control"><?php foreach ($conflict_policies as $value) { ?><option value="<?php echo $value; ?>"<?php echo ($model_info->conflict_policy ?? "reject_series") === $value ? " selected" : ""; ?>><?php echo app_lang("gd_booking_series_conflict_" . $value); ?></option><?php } ?></select></div></div></div>
