    <div class="form-group"><label><?php echo app_lang("gd_resources_and_buffers"); ?></label><div class="table-responsive"><table class="table table-sm"><thead><tr><th></th><th><?php echo app_lang("gd_resource"); ?></th><th><?php echo app_lang("gd_buffer_before"); ?></th><th><?php echo app_lang("gd_buffer_after"); ?></th></tr></thead><tbody><?php foreach ($resources as $resource) { $current = $selected_resources[(int) $resource["id"]] ?? null; ?><tr><td><input type="checkbox" name="resources[<?php echo (int) $resource["id"]; ?>][selected]" value="1"<?php echo $current ? " checked" : ""; ?>></td><td><?php echo $e($resource["code"] . " — " . $resource["name"]); ?></td><td><input type="number" min="0" name="resources[<?php echo (int) $resource["id"]; ?>][buffer_before_minutes]" class="form-control" value="<?php echo (int) ($current->buffer_before_minutes ?? 0); ?>"></td><td><input type="number" min="0" name="resources[<?php echo (int) $resource["id"]; ?>][buffer_after_minutes]" class="form-control" value="<?php echo (int) ($current->buffer_after_minutes ?? 0); ?>"></td></tr><?php } ?></tbody></table></div></div>
