<script>
$(document).ready(function(){
    var form=$("#gd-series-form");
    form.appForm({onSuccess:function(response){location.href='<?php echo_uri("grupo_donato/booking-series/view/"); ?>'+(response.new_series_id||response.id);}});
    function toggle(){var f=$("#gd-series-frequency").val(),e=$("#gd-series-ends-mode").val();$(".gd-weekly-row").toggle(f==="weekly");$(".gd-monthly-row").toggle(f==="monthly");$(".gd-until-row").toggle(e==="until_date");$(".gd-count-row").toggle(e==="count");}
    $("#gd-series-frequency,#gd-series-ends-mode").on("change",toggle);toggle();
    $("#gd-series-preview").on("click",function(){$.post('<?php echo_uri("grupo_donato/booking-series/preview"); ?>',form.serialize()).done(function(response){if(!response.success){appAlert.error(response.message);return;}var rows=response.data||[],html='<div class="table-responsive"><table class="table table-sm"><tr><th>Data</th><th>UTC</th><th>Status</th></tr>';$.each(rows.slice(0,100),function(_,row){html+='<tr><td>'+row.local_date+'</td><td>'+row.starts_at_utc+' — '+row.ends_at_utc+'</td><td>'+(row.available?'✓':'⚠')+'</td></tr>';});html+='</table></div>';$("#gd-series-preview-result").html(html);});});
});
</script>
